import type { HTMLAttributes, ReactNode } from 'react';
export type SidesheetPlacement = 'left' | 'right';
export type SidesheetElevation = 'coplanar' | 'above';
export type SidesheetMode = 'default' | 'modal';
export type SidesheetSize = 'default' | 'large';
export interface SidesheetProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title' | 'content'> {
    /**
     * Сторона с которой панель отображается.
     * @deprecated Скоро свойство будет удалено и сайдшит будет отображаться только справа
     */
    placement?: SidesheetPlacement;
    /**
     * Уровень на котором панель отображается по отношению к содержимому.
     */
    elevation?: SidesheetElevation;
    /**
     * Режим работы панели.
     */
    mode?: SidesheetMode;
    /**
     * Размер панели. По умолчанию 'default' (320px), 'large' (444px).
     */
    size?: SidesheetSize;
    /**
     * Компонент, отображаемый внутри панели.
     */
    content: ReactNode;
    /**
     * Индикатор, добавляющий разделитель для панели.
     */
    hasDivider?: boolean;
    /**
     * Индикатор, добавляющий затемнение над содержимым.
     */
    hasOverlay?: boolean;
    /**
     * Индикатор, открывающий/закрывающий панель.
     */
    isOpen?: boolean;
    /**
     * Обработчик события закрытия панели.
     */
    onClose?: () => void;
    /**
     * Заголовок панели.
     */
    title: ReactNode;
    /**
     * Отключает перенос строк.
     */
    titleNoWrap?: boolean;
    /**
     * Пользовательский стиль
     */
    className?: string;
    /**
     * Кастомные паддинги для контентной области панели.
     * Порядок значений: top, right, bottom, left
     */
    contentPadding?: [number, number, number, number] | string;
    children?: ReactNode;
}
